UPDATE center_manager
SET center_id           = #{centerId}
  , center_manager_code = #{centerManagerCode}
  , center_manager_name = #{centerManagerNameCrypt}
  , no_use              = #{noUse}
  , email               = #{email}
  , telephone           = #{telephone}
  , mobile              = #{mobile}
  , notes               = #{notes}
  , notok_urge          = #{notokUrge}
  , updated_at          = NOW()
  , updated_user_id     = #{sessionUserId}
WHERE user_id = #{userId}

UPDATE company_manager
SET company_id           = #{companyId}
  , company_manager_code = #{companyManagerCode}
  , company_manager_name = #{companyManagerNameCrypt}
  , no_use               = #{noUse}
  , contract             = #{contract}
  , result               = #{result}
  , account              = #{account}
  , email                = #{email}
  , telephone            = #{telephone}
  , mobile               = #{mobile}
  , notes                = #{notes}
  , updated_at           = NOW()
